import{_ as e,o as t,c as a,ag as l}from"./chunks/framework.DXGyWiRo.js";const F=JSON.parse('{"title":"FlashQL Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guides/flashql.md","filePath":"guides/flashql.md"}'),n={name:"guides/flashql.md"};function o(p,s,r,c,i,d){return t(),a("div",null,[...s[0]||(s[0]=[l(`<h1 id="flashql-guide" tabindex="-1">FlashQL Guide <a class="header-anchor" href="#flashql-guide" aria-label="Permalink to &quot;FlashQL Guide&quot;">​</a></h1><p>Unlike the other clients, FlashQL is not a connector to an external database. It is the database itself, a full SQL runtime that runs in the same process as your app.</p><p>Use <code>FlashQL</code> when you want the database to run inside your application, in Node.js, the browser, a worker, or an edge runtime.</p><p>See the <a href="/flashql">FlashQL Overview</a> for architecture and capabilities.</p><hr><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 1::text AS result</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="configuration-shape" tabindex="-1">Configuration Shape <a class="header-anchor" href="#configuration-shape" aria-label="Permalink to &quot;Configuration Shape&quot;">​</a></h2><p>FlashQL is configured entirely at construction time and all parameters are optional:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Option</th><th style="text-align:left;">Type</th><th style="text-align:left;">Default</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>dialect</code></td><td style="text-align:left;"><code>&#39;postgres&#39; | &#39;mysql&#39;</code></td><td style="text-align:left;"><code>&#39;postgres&#39;</code></td><td style="text-align:left;">default SQL dialect</td></tr><tr><td style="text-align:left;"><code>keyval</code></td><td style="text-align:left;"><code>Keyval</code></td><td style="text-align:left;"><code>null</code></td><td style="text-align:left;">enables persistence</td></tr><tr><td style="text-align:left;"><code>getUpstreamClient</code></td><td style="text-align:left;"><code>(origin) =&gt; client</code></td><td style="text-align:left;"><code>null</code></td><td style="text-align:left;">resolves upstream sources</td></tr><tr><td style="text-align:left;"><code>versionStop</code></td><td style="text-align:left;"><code>string | object</code></td><td style="text-align:left;"><code>null</code></td><td style="text-align:left;">boot at a historical point</td></tr><tr><td style="text-align:left;"><code>overwriteForward</code></td><td style="text-align:left;"><code>boolean</code></td><td style="text-align:left;"><code>false</code></td><td style="text-align:left;">allow branching from history</td></tr><tr><td style="text-align:left;"><code>autoSync</code></td><td style="text-align:left;"><code>boolean</code></td><td style="text-align:left;"><code>true</code></td><td style="text-align:left;">run sync on connect</td></tr></tbody></table><p>Example:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> keyval </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> IndexedDBKV</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> path</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">my-app</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> upstream </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> url</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> remoteUrl </span><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mysql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#82AAFF;">  getUpstreamClient</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> ()</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#BABED8;"> upstream</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>FlashQL supports persistence via the <code>keyval</code> parameter.</p><p>See <a href="/flashql#persistence">Persistence</a>.</p><hr><h2 id="upstream-connections" tabindex="-1">Upstream Connections <a class="header-anchor" href="#upstream-connections" aria-label="Permalink to &quot;Upstream Connections&quot;">​</a></h2><p>FlashQL connects to external databases via the <code>getUpstreamClient()</code> callback.</p><p>See <a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a>.</p><hr><h2 id="realtime-notes" tabindex="-1">Realtime Notes <a class="header-anchor" href="#realtime-notes" aria-label="Permalink to &quot;Realtime Notes&quot;">​</a></h2><p>Realtime queries, WAL subscriptions, and sync are built into the runtime. No database-level setup is required.</p><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">the broader FlashQL architecture</td><td style="text-align:left;"><a href="/flashql">FlashQL Overview</a></td></tr><tr><td style="text-align:left;">the common API contract</td><td style="text-align:left;"><a href="/api">Core API</a></td></tr></tbody></table>`,27)])])}const D=e(n,[["render",o]]);export{F as __pageData,D as default};
